-- Create "shops" table
CREATE TABLE "shops" ("id" bigint NOT NULL GENERATED BY DEFAULT AS IDENTITY, "name" character varying NOT NULL, "timezone" character varying NOT NULL DEFAULT 'UTC', "invite_code" character varying NOT NULL, "owner_telegram_id" bigint NOT NULL, "created_at" timestamptz NOT NULL, PRIMARY KEY ("id"));
-- Create index "shops_invite_code_key" to table: "shops"
CREATE UNIQUE INDEX "shops_invite_code_key" ON "shops" ("invite_code");
-- Create "employees" table
CREATE TABLE "employees" ("id" bigint NOT NULL GENERATED BY DEFAULT AS IDENTITY, "telegram_user_id" bigint NOT NULL, "display_name" character varying NOT NULL, "max_hours_per_week" double precision NOT NULL DEFAULT 40, "active" boolean NOT NULL DEFAULT true, "created_at" timestamptz NOT NULL, "shop_id" bigint NOT NULL, PRIMARY KEY ("id"), CONSTRAINT "employees_shops_employees" FOREIGN KEY ("shop_id") REFERENCES "shops" ("id") ON UPDATE NO ACTION ON DELETE CASCADE);
-- Create index "employee_shop_id_telegram_user_id" to table: "employees"
CREATE UNIQUE INDEX "employee_shop_id_telegram_user_id" ON "employees" ("shop_id", "telegram_user_id");
-- Create index "employee_telegram_user_id" to table: "employees"
CREATE INDEX "employee_telegram_user_id" ON "employees" ("telegram_user_id");
-- Create "availabilities" table
CREATE TABLE "availabilities" ("id" bigint NOT NULL GENERATED BY DEFAULT AS IDENTITY, "week_start" date NOT NULL, "starts_at" timestamptz NOT NULL, "ends_at" timestamptz NOT NULL, "preference" bigint NOT NULL DEFAULT 1, "note" character varying NOT NULL DEFAULT '', "raw_text" text NOT NULL DEFAULT '', "created_at" timestamptz NOT NULL, "employee_id" bigint NOT NULL, "shop_id" bigint NOT NULL, PRIMARY KEY ("id"), CONSTRAINT "availabilities_employees_availability" FOREIGN KEY ("employee_id") REFERENCES "employees" ("id") ON UPDATE NO ACTION ON DELETE CASCADE, CONSTRAINT "availabilities_shops_availability" FOREIGN KEY ("shop_id") REFERENCES "shops" ("id") ON UPDATE NO ACTION ON DELETE CASCADE);
-- Create index "availability_employee_id_week_start" to table: "availabilities"
CREATE INDEX "availability_employee_id_week_start" ON "availabilities" ("employee_id", "week_start");
-- Create index "availability_shop_id_week_start" to table: "availabilities"
CREATE INDEX "availability_shop_id_week_start" ON "availabilities" ("shop_id", "week_start");
-- Create "rules" table
CREATE TABLE "rules" ("id" bigint NOT NULL GENERATED BY DEFAULT AS IDENTITY, "kind" character varying NOT NULL, "params" jsonb NULL, "weight" double precision NOT NULL DEFAULT 1, "source_text" text NOT NULL DEFAULT '', "active" boolean NOT NULL DEFAULT true, "created_at" timestamptz NOT NULL, "shop_id" bigint NOT NULL, PRIMARY KEY ("id"), CONSTRAINT "rules_shops_rules" FOREIGN KEY ("shop_id") REFERENCES "shops" ("id") ON UPDATE NO ACTION ON DELETE CASCADE);
-- Create index "rule_shop_id_active" to table: "rules"
CREATE INDEX "rule_shop_id_active" ON "rules" ("shop_id", "active");
-- Create "schedules" table
CREATE TABLE "schedules" ("id" bigint NOT NULL GENERATED BY DEFAULT AS IDENTITY, "week_start" date NOT NULL, "label" character varying NOT NULL DEFAULT '', "status" character varying NOT NULL DEFAULT 'draft', "score" double precision NOT NULL DEFAULT 0, "created_at" timestamptz NOT NULL, "shop_id" bigint NOT NULL, PRIMARY KEY ("id"), CONSTRAINT "schedules_shops_schedules" FOREIGN KEY ("shop_id") REFERENCES "shops" ("id") ON UPDATE NO ACTION ON DELETE CASCADE);
-- Create index "schedule_shop_id_week_start" to table: "schedules"
CREATE INDEX "schedule_shop_id_week_start" ON "schedules" ("shop_id", "week_start");
-- Create "shifts" table
CREATE TABLE "shifts" ("id" bigint NOT NULL GENERATED BY DEFAULT AS IDENTITY, "role" character varying NOT NULL DEFAULT '', "starts_at" timestamptz NOT NULL, "ends_at" timestamptz NOT NULL, "min_staff" bigint NOT NULL DEFAULT 1, "max_staff" bigint NOT NULL DEFAULT 1, "created_at" timestamptz NOT NULL, "shop_id" bigint NOT NULL, PRIMARY KEY ("id"), CONSTRAINT "shifts_shops_shifts" FOREIGN KEY ("shop_id") REFERENCES "shops" ("id") ON UPDATE NO ACTION ON DELETE CASCADE);
-- Create index "shift_shop_id_starts_at" to table: "shifts"
CREATE INDEX "shift_shop_id_starts_at" ON "shifts" ("shop_id", "starts_at");
-- Create "schedule_assignments" table
CREATE TABLE "schedule_assignments" ("id" bigint NOT NULL GENERATED BY DEFAULT AS IDENTITY, "employee_id" bigint NOT NULL, "schedule_id" bigint NOT NULL, "shift_id" bigint NOT NULL, "shop_id" bigint NOT NULL, PRIMARY KEY ("id"), CONSTRAINT "schedule_assignments_employees_assignments" FOREIGN KEY ("employee_id") REFERENCES "employees" ("id") ON UPDATE NO ACTION ON DELETE CASCADE, CONSTRAINT "schedule_assignments_schedules_assignments" FOREIGN KEY ("schedule_id") REFERENCES "schedules" ("id") ON UPDATE NO ACTION ON DELETE CASCADE, CONSTRAINT "schedule_assignments_shifts_assignments" FOREIGN KEY ("shift_id") REFERENCES "shifts" ("id") ON UPDATE NO ACTION ON DELETE CASCADE, CONSTRAINT "schedule_assignments_shops_assignments" FOREIGN KEY ("shop_id") REFERENCES "shops" ("id") ON UPDATE NO ACTION ON DELETE CASCADE);
-- Create index "scheduleassignment_schedule_id" to table: "schedule_assignments"
CREATE INDEX "scheduleassignment_schedule_id" ON "schedule_assignments" ("schedule_id");
-- Create index "scheduleassignment_schedule_id_shift_id_employee_id" to table: "schedule_assignments"
CREATE UNIQUE INDEX "scheduleassignment_schedule_id_shift_id_employee_id" ON "schedule_assignments" ("schedule_id", "shift_id", "employee_id");
-- Create "schedule_votes" table
CREATE TABLE "schedule_votes" ("id" bigint NOT NULL GENERATED BY DEFAULT AS IDENTITY, "created_at" timestamptz NOT NULL, "employee_id" bigint NOT NULL, "schedule_id" bigint NOT NULL, "shop_id" bigint NOT NULL, PRIMARY KEY ("id"), CONSTRAINT "schedule_votes_employees_votes" FOREIGN KEY ("employee_id") REFERENCES "employees" ("id") ON UPDATE NO ACTION ON DELETE CASCADE, CONSTRAINT "schedule_votes_schedules_votes" FOREIGN KEY ("schedule_id") REFERENCES "schedules" ("id") ON UPDATE NO ACTION ON DELETE CASCADE, CONSTRAINT "schedule_votes_shops_votes" FOREIGN KEY ("shop_id") REFERENCES "shops" ("id") ON UPDATE NO ACTION ON DELETE CASCADE);
-- Create index "schedulevote_schedule_id_employee_id" to table: "schedule_votes"
CREATE UNIQUE INDEX "schedulevote_schedule_id_employee_id" ON "schedule_votes" ("schedule_id", "employee_id");
-- Create index "schedulevote_shop_id" to table: "schedule_votes"
CREATE INDEX "schedulevote_shop_id" ON "schedule_votes" ("shop_id");
